// ESG Scoring Calculator
// Accepts environmental metrics and calculates comprehensive ESG scores

// Parse the input query (expecting JSON string or object)
let metrics;
try {
  metrics = typeof query === 'string' ? JSON.parse(query) : query;
} catch (e) {
  return JSON.stringify({ error: 'Invalid input format. Expected JSON with carbon, energy, and resource data.' });
}

const carbon = metrics.carbonFootprint || metrics.carbon || 0;
const energy = metrics.energyConsumption || metrics.energy || 0;
const resources = metrics.resourceUtilization || metrics.resources || 0;

// Calculate Carbon Efficiency Score (0-100, lower carbon is better)
const carbonScore = Math.max(0, 100 - (carbon / 50)); // Assuming 5000kg is poor, 0 is perfect

// Calculate Energy Efficiency Score (0-100, lower consumption is better)
const energyScore = Math.max(0, 100 - (energy / 100)); // Assuming 10000kWh is poor, 0 is perfect

// Resource Utilization Score (already a percentage, higher is better)
const resourceScore = Math.min(100, resources);

// Overall ESG Score (weighted average)
const esgScore = (carbonScore * 0.4 + energyScore * 0.35 + resourceScore * 0.25).toFixed(2);

// Energy Efficiency Rating
let energyRating;
if (energyScore >= 90) energyRating = 'A+';
else if (energyScore >= 80) energyRating = 'A';
else if (energyScore >= 70) energyRating = 'B';
else if (energyScore >= 60) energyRating = 'C';
else energyRating = 'D';

// Risk Level Assessment
let riskLevel;
if (esgScore >= 80) riskLevel = 'low';
else if (esgScore >= 60) riskLevel = 'medium';
else riskLevel = 'high';

// Compliance Status
const complianceStatus = esgScore >= 70 ? 'compliant' : 'non-compliant';

// Build result object
const result = {
  esgScore: parseFloat(esgScore),
  carbonScore: parseFloat(carbonScore.toFixed(2)),
  energyScore: parseFloat(energyScore.toFixed(2)),
  resourceScore: parseFloat(resourceScore.toFixed(2)),
  energyEfficiencyRating: energyRating,
  riskLevel: riskLevel,
  complianceStatus: complianceStatus,
  carbonFootprintValidated: carbon,
  energyConsumptionValidated: energy,
  resourceUtilizationValidated: resources,
  sustainabilityKPIs: {
    carbonEfficiency: carbonScore,
    energyEfficiency: energyScore,
    resourceOptimization: resourceScore
  }
};

return JSON.stringify(result, null, 2);

